18	pub fn parse(
19	    globalThis: *jsc.JSGlobalObject,
20	    callframe: *jsc.CallFrame,
21	) bun.JSError!jsc.JSValue {
22	    var arena = bun.ArenaAllocator.init(globalThis.allocator());
23	    const allocator = arena.allocator();
24	    defer arena.deinit();
25	
26	    var ast_memory_allocator = bun.handleOom(allocator.create(ast.ASTMemoryAllocator));
27	    var ast_scope = ast_memory_allocator.enter(allocator);
28	    defer ast_scope.exit();
29	
30	    var log = logger.Log.init(default_allocator);
31	    defer log.deinit();
32	    const input_value = callframe.argument(0);
33	    if (input_value.isEmptyOrUndefinedOrNull()) {
34	        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
35	    }
36	
37	    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
38	    defer input_slice.deinit();
39	    const source = &logger.Source.initPathString("input.jsonc", input_slice.slice());
40	    const parse_result = json.parseTSConfig(source, &log, allocator, true) catch |err| {
41	        if (err == error.StackOverflow) {
42	            return globalThis.throwStackOverflow();
43	        }
44	        return globalThis.throwValue(try log.toJS(globalThis, default_allocator, "Failed to parse JSONC"));
45	    };
46	
47	    return parse_result.toJS(allocator, globalThis) catch |err| switch (err) {
48	        error.OutOfMemory => return error.OutOfMemory,
49	        error.JSError => return error.JSError,
50	        error.JSTerminated => return error.JSTerminated,
51	        // JSONC parsing does not produce macros or identifiers
52	        else => unreachable,
53	    };
