138	    pub fn init(global: *jsc.JSGlobalObject, space_value: JSValue) bun.JSError!Stringifier {
139	        return .{
140	            .stack_check = .init(),
141	            .builder = .init(),
142	            .indent = 0,
143	            .space = try Space.init(global, space_value),
144	            .visiting = .empty,
145	            .allocator = bun.default_allocator,
146	        };
147	    }
148	
149	    pub fn deinit(this: *Stringifier) void {
150	        this.builder.deinit();
151	        this.space.deinit();
152	        this.visiting.deinit(this.allocator);
153	    }
154	
155	    pub fn stringifyValue(this: *Stringifier, global: *jsc.JSGlobalObject, value: JSValue) StringifyError!void {
156	        if (!this.stack_check.isSafeToRecurse()) {
157	            return error.StackOverflow;
158	        }
159	
160	        const unwrapped = try value.unwrapBoxedPrimitive(global);
161	
162	        if (unwrapped.isNull()) {
163	            this.builder.append(.latin1, "null");
164	            return;
165	        }
166	
167	        if (unwrapped.isNumber()) {
168	            if (unwrapped.isInt32()) {
169	                this.builder.append(.int, unwrapped.asInt32());
170	                return;
171	            }
172	            const num = unwrapped.asNumber();
173	            if (std.math.isNegativeInf(num)) {
174	                this.builder.append(.latin1, "-Infinity");
175	            } else if (std.math.isInf(num)) {
176	                this.builder.append(.latin1, "Infinity");
177	            } else if (std.math.isNan(num)) {
178	                this.builder.append(.latin1, "NaN");
179	            } else {
180	                this.builder.append(.double, num);
181	            }
182	            return;
183	        }
184	
185	        if (unwrapped.isBigInt()) {
186	            return global.throw("JSON5.stringify cannot serialize BigInt", .{});
187	        }
188	
189	        if (unwrapped.isBoolean()) {
190	            this.builder.append(.latin1, if (unwrapped.asBoolean()) "true" else "false");
191	            return;
192	        }
193	
194	        if (unwrapped.isString()) {
195	            const str = try unwrapped.toBunString(global);
196	            defer str.deref();
197	            this.appendQuotedString(str);
198	            return;
199	        }
200	
201	        // Object or array — check for circular references
202	        const gop = try this.visiting.getOrPut(this.allocator, unwrapped);
203	        if (gop.found_existing) {
204	            return global.throw("Converting circular structure to JSON5", .{});
205	        }
206	        defer _ = this.visiting.remove(unwrapped);
207	
208	        if (unwrapped.isArray()) {
209	            try this.stringifyArray(global, unwrapped);
210	        } else {
211	            try this.stringifyObject(global, unwrapped);
212	        }
213	    }
214	
215	    fn stringifyArray(this: *Stringifier, global: *jsc.JSGlobalObject, value: JSValue) StringifyError!void {
216	        var iter = try value.arrayIterator(global);
217	
218	        if (iter.len == 0) {
219	            this.builder.append(.latin1, "[]");
220	            return;
221	        }
222	
223	        this.builder.append(.lchar, '[');
224	
225	        switch (this.space) {
226	            .minified => {
227	                var first = true;
228	                while (try iter.next()) |item| {
229	                    if (!first) this.builder.append(.lchar, ',');
230	                    first = false;
231	                    if (item.isUndefined() or item.isSymbol() or item.isFunction()) {
232	                        this.builder.append(.latin1, "null");
233	                    } else {
234	                        try this.stringifyValue(global, item);
235	                    }
236	                }
237	            },
238	            .number, .str => {
239	                this.indent += 1;
240	                var first = true;
241	                while (try iter.next()) |item| {
242	                    if (!first) this.builder.append(.lchar, ',');
243	                    first = false;
244	                    this.newline();
245	                    if (item.isUndefined() or item.isSymbol() or item.isFunction()) {
246	                        this.builder.append(.latin1, "null");
247	                    } else {
248	                        try this.stringifyValue(global, item);
249	                    }
250	                }
251	                // Trailing comma
252	                this.builder.append(.lchar, ',');
253	                this.indent -= 1;
254	                this.newline();
255	            },
256	        }
257	
258	        this.builder.append(.lchar, ']');
259	    }
260	
261	    fn stringifyObject(this: *Stringifier, global: *jsc.JSGlobalObject, value: JSValue) StringifyError!void {
262	        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
263	            global,
264	            try value.toObject(global),
265	        );
266	        defer iter.deinit();
267	
268	        if (iter.len == 0) {
269	            this.builder.append(.latin1, "{}");
270	            return;
271	        }
272	
273	        this.builder.append(.lchar, '{');
274	
275	        switch (this.space) {
276	            .minified => {
277	                var first = true;
278	                while (try iter.next()) |prop_name| {
279	                    if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
280	                        continue;
281	                    }
282	                    if (!first) this.builder.append(.lchar, ',');
283	                    first = false;
284	                    this.appendKey(prop_name);
285	                    this.builder.append(.lchar, ':');
286	                    try this.stringifyValue(global, iter.value);
287	                }
288	            },
289	            .number, .str => {
290	                this.indent += 1;
291	                var first = true;
292	                while (try iter.next()) |prop_name| {
293	                    if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
294	                        continue;
295	                    }
296	                    if (!first) this.builder.append(.lchar, ',');
297	                    first = false;
298	                    this.newline();
299	                    this.appendKey(prop_name);
300	                    this.builder.append(.latin1, ": ");
301	                    try this.stringifyValue(global, iter.value);
302	                }
303	                this.indent -= 1;
304	                if (!first) {
305	                    // Trailing comma
306	                    this.builder.append(.lchar, ',');
307	                    this.newline();
308	                }
309	            },
310	        }
311	
312	        this.builder.append(.lchar, '}');
313	    }
314	
315	    fn appendKey(this: *Stringifier, name: bun.String) void {
316	        const is_identifier = is_identifier: {
317	            if (name.length() == 0) break :is_identifier false;
318	            if (!bun.js_lexer.isIdentifierStart(@intCast(name.charAt(0)))) break :is_identifier false;
319	            for (1..name.length()) |i| {
320	                if (!bun.js_lexer.isIdentifierContinue(@intCast(name.charAt(i)))) break :is_identifier false;
321	            }
322	            break :is_identifier true;
323	        };
324	
325	        if (is_identifier) {
326	            this.builder.append(.string, name);
327	        } else {
328	            this.appendQuotedString(name);
329	        }
330	    }
331	
332	    fn appendQuotedString(this: *Stringifier, str: bun.String) void {
333	        this.builder.append(.lchar, '\'');
334	        for (0..str.length()) |i| {
335	            const c = str.charAt(i);
336	            switch (c) {
337	                0x00 => this.builder.append(.latin1, "\\0"),
338	                0x08 => this.builder.append(.latin1, "\\b"),
339	                0x09 => this.builder.append(.latin1, "\\t"),
340	                0x0a => this.builder.append(.latin1, "\\n"),
341	                0x0b => this.builder.append(.latin1, "\\v"),
342	                0x0c => this.builder.append(.latin1, "\\f"),
343	                0x0d => this.builder.append(.latin1, "\\r"),
344	                0x27 => this.builder.append(.latin1, "\\'"), // single quote
345	                0x5c => this.builder.append(.latin1, "\\\\"), // backslash
346	                0x2028 => this.builder.append(.latin1, "\\u2028"),
347	                0x2029 => this.builder.append(.latin1, "\\u2029"),
348	                0x01...0x07, 0x0e...0x1f, 0x7f => {
349	                    // Other control chars → \xHH
350	                    this.builder.append(.latin1, "\\x");
351	                    this.builder.append(.lchar, hexDigit(c >> 4));
352	                    this.builder.append(.lchar, hexDigit(c & 0x0f));
353	                },
354	                else => this.builder.append(.uchar, c),
355	            }
356	        }
357	        this.builder.append(.lchar, '\'');
358	    }
359	
360	    fn hexDigit(v: u16) u8 {
361	        const nibble: u8 = @intCast(v & 0x0f);
362	        return if (nibble < 10) '0' + nibble else 'a' + nibble - 10;
363	    }
364	
365	    fn newline(this: *Stringifier) void {
366	        switch (this.space) {
367	            .minified => {},
368	            .number => |space_num| {
369	                this.builder.append(.lchar, '\n');
370	                for (0..this.indent * space_num) |_| {
371	                    this.builder.append(.lchar, ' ');
372	                }
373	            },
374	            .str => |space_str| {
375	                this.builder.append(.lchar, '\n');
376	                const clamped = if (space_str.length() > 10)
377	                    space_str.substringWithLen(0, 10)
378	                else
379	                    space_str;
380	                for (0..this.indent) |_| {
381	                    this.builder.append(.string, clamped);
382	                }
383	            },
384	        }
385	    }
386	};
