    object.put(globalThis, ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 3, .{}),
    );
    return object;
}

pub fn stringify(global: *JSGlobalObject, callFrame: *jsc.CallFrame) JSError!JSValue {
    var stringifier: Stringifier = try .init(scope.allocator(), global, space_value);
    defer stringifier.deinit();

    // First pass: find anchors and aliases (handles circular references)
    stringifier.findAnchorsAndAliases(global, value, .root) catch |err| {
        // Error handling
    };

    // Second pass: stringify with anchor/alias support
    stringifier.stringify(global, value) catch |err| {
        // Error handling
    };

    return stringifier.builder.toString(global);
}
```

**Advanced Features**:
- **Anchor/Alias System**: Detects circular references and reuse
- **Flow vs Block Style**: Minified (flow-style) vs pretty-printed (block-style)
- **Quote Detection**: Smart quoting for YAML keywords and special chars
- **Null Number Handling**: Proper YAML representation (`.inf`, `.nan`, `-0`, `+0`)

---

### 2. **Registration Layer** - BunObject.zig

The format objects are registered as **lazy properties**:

```zig
// In BunObject declarations (lines 66-70):
pub const JSONC = toJSLazyPropertyCallback(Bun.getJSONCObject);
pub const TOML = toJSLazyPropertyCallback(Bun.getTOMLObject);
pub const JSON5 = toJSLazyPropertyCallback(Bun.getJSON5Object);
pub const YAML = toJSLazyPropertyCallback(Bun.getYAMLObject);

// In BunObject exports (lines 136-140):
@export(&BunObject.JSONC, .{ .name = lazyPropertyCallbackName("JSONC") });
@export(&BunObject.TOML, .{ .name = lazyPropertyCallbackName("TOML") });
@export(&BunObject.JSON5, .{ .name = lazyPropertyCallbackName("JSON5") });
@export(&BunObject.YAML, .{ .name = lazyPropertyCallbackName("YAML") });

// Getter functions (lines 1273-1289):
pub fn getJSONCObject(globalThis: *jsc.JSGlobalObject, _: *jsc.JSObject) jsc.JSValue {
    return JSONCObject.create(globalThis);
}

pub fn getTOMLObject(globalThis: *jsc.JSGlobalObject, _: *jsc.JSObject) jsc.JSValue {
    return TOMLObject.create(globalThis);
}

pub fn getJSON5Object(globalThis: *jsc.JSGlobalObject, _: *jsc.JSObject) jsc.JSValue {
    return JSON5Object.create(globalThis);
}

pub fn getYAMLObject(globalThis: *jsc.JSGlobalObject, _: *jsc.JSObject) jsc.JSValue {
    return YAMLObject.create(globalThis);
}
```

**Key Pattern**: Each getter calls the object's `create()` function which:
1. Creates an empty JS object
2. Adds method properties (parse, stringify)
3. Returns the populated object

**Lazy Loading**: Objects aren't created until accessed, improving startup performance.

---

### 3. **Module Imports** - api.zig

Central module that exports all API objects:

```zig
// src/bun.js/api.zig
pub const JSONCObject = @import("./api/JSONCObject.zig");
pub const TOMLObject = @import("./api/TOMLObject.zig");
pub const JSON5Object = @import("./api/JSON5Object.zig");
pub const YAMLObject = @import("./api/YAMLObject.zig");
```

Then imported into BunObject:
```zig
const api = bun.api;
const JSON5Object = bun.api.JSON5Object;
const JSONCObject = bun.api.JSONCObject;
const TOMLObject = bun.api.TOMLObject;
const YAMLObject = bun.api.YAMLObject;
```

---

### 4. **TypeScript Type Definitions** - packages/bun-types/bun.d.ts

Each format is defined as a namespace on the `Bun` global:

```typescript
namespace TOML {
  export function parse(input: string): object;
}

namespace JSONC {
  export function parse(input: string): unknown;
}

namespace JSON5 {
  export function parse(input: string): unknown;
  export function stringify(input: unknown, replacer?: undefined | null, space?: string | number): string | undefined;
}

namespace YAML {
  export function parse(input: string): unknown;
  export function stringify(
    input: unknown,
    replacer?: undefined | null,
    space?: string | number,
  ): string;
}
```

**Notable Difference**: 
- `TOML`: Only has `parse()`, no stringify
- `JSON5` & `YAML`: Have both `parse()` and `stringify()`
- `JSONC`: Only has `parse()`, no stringify

---

### 5. **Actual Parsers** - src/interchange/

The Zig bindings delegate to core parsers:

```
src/interchange/
├── toml.zig          ← TOML.parse() implementation
├── toml/
│   └── lexer.zig
├── json.zig          ← JSON/JSONC implementation (json.parseTSConfig)
├── json5.zig         ← JSON5 parser
└── yaml.zig          ← YAML parser
```

**Critical Implementation Details**:

**TOML** (TOMLObject.zig line 73):
```zig
const TOML = bun.interchange.toml.TOML;
const parse_result = TOML.parse(source, &log, allocator, false) catch |err| { ... };
```

**JSONC** (JSONCObject.zig line 60):
```zig
const json = bun.interchange.json;
const parse_result = json.parseTSConfig(source, &log, allocator, true) catch |err| { ... };
```
Note: Uses `parseTSConfig` with `true` flag to enable comment support

**JSON5** (JSON5Object.zig line 425):
```zig
const json5 = bun.interchange.json5;
const root = json5.JSON5Parser.parse(source, &log, allocator) catch |err| { ... };
```

**YAML** (YAMLObject.zig line 1084):
```zig
const YAML = bun.interchange.yaml.YAML;
const root = bun.interchange.yaml.YAML.parse(source, &log, arena.allocator()) catch |err| { ... };
```

---

### 6. **Complete Request Flow Example**

When you call `Bun.JSON5.stringify()`:

1. **JS Layer**: User calls `Bun.JSON5.stringify(value, null, 2)`
2. **Lazy Property Access**: BunObject's `JSON5` lazy property callback triggers
3. **Object Creation**: `Bun.getJSON5Object()` → `JSON5Object.create(globalThis)`
4. **Method Invocation**: JS calls the `stringify` function pointer
5. **Zig Handler**: `JSON5Object.stringify()` executes:
   - Validates arguments via `callFrame.argumentsAsArray(3)`
   - Creates `Stringifier` struct with space parameter
   - Calls `stringifyValue()` recursively
   - Uses `wtf.StringBuilder` to accumulate output
   - Handles JSON5-specific features (unquoted keys, trailing commas, Infinity, NaN)
   - Returns `stringifier.builder.toString(global)` as JS string value
6. **Error Handling**: Catches OOM, JSError, StackOverflow and converts to JS exceptions

---

### 7. **Key Implementation Patterns**

**Object Creation Pattern**:
```zig
pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, N);  // N = number of properties
    object.put(globalThis, propertyName, jsFunction);
    return object;
}
```

**Method Registration Pattern**:
```zig
object.put(
    globalThis,
    ZigString.static("methodName"),
    jsc.JSFunction.create(
        globalThis,
        "methodName",
        functionPtr,
        argCount,
        .{},
    ),
);
```

**Error Conversion Pattern**:
```zig
try someParser.parse(...) catch |err| return switch (err) {
    error.OutOfMemory => error.OutOfMemory,
    error.StackOverflow => global.throwStackOverflow(),
    else => global.throwValue(try log.toJS(globalThis, default_allocator, "Error message")),
};
```

**Lazy Property Pattern** (BunObject.zig):
```zig
pub const YAML = toJSLazyPropertyCallback(Bun.getYAMLObject);
// Exported with:
@export(&BunObject.YAML, .{ .name = lazyPropertyCallbackName("YAML") });
```

---

### 8. **Test Examples**

From `test/js/bun/jsonc/jsonc.test.ts`:
```typescript
import { expect, test } from "bun:test";

test("Bun.JSONC.parse handles comments", () => {
  const jsonc = `{
    // This is a comment
    "name": "test",
    /* This is a block comment */
    "value": 42
  }`;
  const result = Bun.JSONC.parse(jsonc);
  expect(result).toEqual({ name: "test", value: 42 });
});
```

From `test/js/bun/yaml/yaml.test.ts`:
```typescript
import { YAML, file } from "bun";

test("Bun.YAML parses from Buffer", () => {
  const buffer = Buffer.from("key: value\nnumber: 42");
  expect(YAML.parse(buffer)).toEqual({ key: "value", number: 42 });
});

test("YAML.stringify with indentation", () => {
  const input = { abc: "def", num: 123 };
  // Without space - flow style
  console.log(YAML.stringify(input));  // {abc: def,num: 123}
  // With space - block style
  console.log(YAML.stringify(input, null, 2));
  // abc: def
  // num: 123
});
```

---

### Summary: Implementation Architecture

```
┌─────────────────────────────────────────────────────────────┐
│ TypeScript Definitions (packages/bun-types/bun.d.ts)        │
│ - Namespace declarations (TOML, JSONC, JSON5, YAML)         │
│ - Function signatures (parse, stringify)                     │
└──────────────────────┬──────────────────────────────────────┘
                       │
┌──────────────────────▼──────────────────────────────────────┐
│ Registration Layer (src/bun.js/api/BunObject.zig)            │
│ - Lazy property callbacks                                    │
│ - Getter functions (getTOMLObject, getJSON5Object, etc)     │
│ - Property exports with names                               │
└──────────────────────┬──────────────────────────────────────┘
                       │
┌──────────────────────▼──────────────────────────────────────┐
│ Binding Objects (src/bun.js/api/)                           │
│ - TOMLObject.zig → creates parse method                     │
│ - JSONCObject.zig → creates parse method                    │
│ - JSON5Object.zig → creates parse + stringify methods       │
│ - YAMLObject.zig → creates parse + stringify methods        │
└──────────────────────┬──────────────────────────────────────┘
                       │
┌──────────────────────▼──────────────────────────────────────┐
│ Core Parsers (src/interchange/)                             │
│ - toml.zig (TOML.parse)                                     │
│ - json.zig (json.parseTSConfig for JSONC)                  │
│ - json5.zig (JSON5Parser.parse)                             │
│ - yaml.zig (YAML.parse, Stringifier for stringify)         │
└─────────────────────────────────────────────────────────────┘
```

This architecture achieves:
- **Lazy Loading**: Objects created only on access
- **Type Safety**: Zig compiler enforces proper error handling
- **Performance**: Direct Zig→JS bindings, no intermediate allocations
- **Maintainability**: Clear separation between API definition and implementation

