pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callframe.argument(0);
    if (input_value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
    defer input_slice.deinit();

    return parseSlice(globalThis, input_slice.slice());
}

fn parseSlice(globalThis: *jsc.JSGlobalObject, input: []const u8) bun.JSError!jsc.JSValue {
    const root = JSValue.createEmptyObject(globalThis, 8);
    var current_section = root;

    var remaining = input;
    while (remaining.len > 0) {
        // Find end of line
        const line_end = std.mem.indexOfScalar(u8, remaining, '\n') orelse remaining.len;
        const raw_line = remaining[0..line_end];
        remaining = if (line_end < remaining.len) remaining[line_end + 1 ..] else "";

        // Strip carriage return
        const cr_stripped = if (raw_line.len > 0 and raw_line[raw_line.len - 1] == '\r')
            raw_line[0 .. raw_line.len - 1]
        else
            raw_line;

        const line = std.mem.trim(u8, cr_stripped, " \t");

        if (line.len == 0) continue;
        if (line[0] == ';' or line[0] == '#') continue;

        if (line[0] == '[') {
            if (std.mem.indexOfScalar(u8, line, ']')) |close| {
                const section_name = std.mem.trim(u8, line[1..close], " \t");
                if (section_name.len > 0) {
                    const section_obj = JSValue.createEmptyObject(globalThis, 8);
                    var key = bun.String.borrowUTF8(section_name);
                    try root.putMayBeIndex(globalThis, &key, section_obj);
                    current_section = section_obj;
                }
            }
            continue;
        }

        if (std.mem.indexOfScalar(u8, line, '=')) |eq_pos| {
            const key_str = std.mem.trim(u8, line[0..eq_pos], " \t");
            if (key_str.len == 0) continue;

            const value_raw = std.mem.trim(u8, line[eq_pos + 1 ..], " \t");
            const value_str = extractValue(value_raw);

            var key = bun.String.borrowUTF8(key_str);
            var val = bun.String.borrowUTF8(value_str);
            const js_val = val.toJS(globalThis);
            try current_section.putMayBeIndex(globalThis, &key, js_val);
        }
    }

    return root;
}

/// Extract the effective value from a raw INI value string.
/// Handles double-quoted and single-quoted strings, and strips inline `;`/`#` comments.
fn extractValue(raw: []const u8) []const u8 {
    if (raw.len == 0) return raw;

    // Double-quoted string — scan to closing quote, honouring backslash escapes.
    if (raw[0] == '"') {
        var i: usize = 1;
        while (i < raw.len) : (i += 1) {
            if (raw[i] == '\\' and i + 1 < raw.len) {
                i += 1;
                continue;
            }
            if (raw[i] == '"') return raw[1..i];
        }
        return raw[1..]; // unterminated quote — return everything after the opening quote
    }

    // Single-quoted string
    if (raw[0] == '\'') {
        if (std.mem.indexOfScalar(u8, raw[1..], '\'')) |end| {
            return raw[1 .. 1 + end];
        }
        return raw[1..]; // unterminated
    }

    // Unquoted — strip trailing inline comment (`;` or `#`).
    for (0..raw.len) |i| {
        if (raw[i] == ';' or raw[i] == '#') {
            return std.mem.trimRight(u8, raw[0..i], " \t");
        }
    }

    return raw;
}

pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callframe.argument(0);

    if (input_value.isUndefined()) return .js_undefined;
    if (input_value.isEmptyOrUndefinedOrNull() or !input_value.isObject()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    var builder = jsc.wtf.StringBuilder.init();
    defer builder.deinit();

    try stringifyRootObject(globalThis, &builder, input_value);

    return builder.toString(globalThis);
}

fn stringifyRootObject(
    globalThis: *jsc.JSGlobalObject,
    builder: *jsc.wtf.StringBuilder,
    obj: JSValue,
) bun.JSError!void {
    // Pass 1: write top-level scalar (non-object) properties without a section header.
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try obj.toObject(globalThis),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const val = iter.value;
            // Skip plain objects — they will be written as sections in pass 2.
            if (val.isObject() and !val.isArray()) continue;
            try appendKeyValue(globalThis, builder, prop_name, val);
        }
    }

    // Pass 2: write top-level plain-object properties as INI sections.
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try obj.toObject(globalThis),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const val = iter.value;
            if (!val.isObject() or val.isArray()) continue;

            // Section header
            builder.append(.lchar, '\n');
            builder.append(.lchar, '[');
            builder.append(.string, prop_name);
            builder.append(.lchar, ']');
            builder.append(.lchar, '\n');

            // Section key-value pairs (one level deep; nested objects are skipped).
            var section_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
                globalThis,
                try val.toObject(globalThis),
            );
            defer section_iter.deinit();

            while (try section_iter.next()) |key| {
                try appendKeyValue(globalThis, builder, key, section_iter.value);
            }
        }
    }
}

/// Write a single `key = value\n` line to `builder`.
/// Skips values that cannot be represented as an INI scalar (plain objects, symbols, functions).
fn appendKeyValue(
    globalThis: *jsc.JSGlobalObject,
    builder: *jsc.wtf.StringBuilder,
    key: bun.String,
    value: JSValue,
) bun.JSError!void {
    if (value.isSymbol() or value.isFunction() or value.isUndefined()) return;
    // Nested plain objects are not supported inside a section.
    if (value.isObject() and !value.isArray()) return;

    builder.append(.string, key);
    builder.append(.latin1, " = ");

    if (value.isNull()) {
        // Write an empty value.
    } else if (value.isBoolean()) {
        builder.append(.latin1, if (value.asBoolean()) "true" else "false");
    } else if (value.isNumber()) {
        if (value.isInt32()) {
            builder.append(.int, value.asInt32());
        } else {
            builder.append(.double, value.asNumber());
        }
    } else if (value.isString()) {
        const str = try value.toBunString(globalThis);
        defer str.deref();
        appendStringValue(builder, str);
    } else if (value.isArray()) {
        // Write array elements as a comma-separated list.
        var arr_iter = try value.arrayIterator(globalThis);
        var first = true;
        while (try arr_iter.next()) |item| {
            if (item.isUndefined() or item.isSymbol() or item.isFunction()) continue;
            if (!first) builder.append(.lchar, ',');
            first = false;
            try appendScalar(globalThis, builder, item);
        }
    }

    builder.append(.lchar, '\n');
}

/// Append a scalar JS value (not object/array) to `builder`.
fn appendScalar(
    globalThis: *jsc.JSGlobalObject,
    builder: *jsc.wtf.StringBuilder,
    value: JSValue,
) bun.JSError!void {
    if (value.isNull()) {
        // empty
    } else if (value.isBoolean()) {
        builder.append(.latin1, if (value.asBoolean()) "true" else "false");
    } else if (value.isNumber()) {
        if (value.isInt32()) {
            builder.append(.int, value.asInt32());
        } else {
            builder.append(.double, value.asNumber());
        }
    } else if (value.isString()) {
        const str = try value.toBunString(globalThis);
        defer str.deref();
        appendStringValue(builder, str);
    }
}

/// Append a string value, wrapping it in double quotes if it contains characters
/// that could be misinterpreted by an INI parser (`;`, `#`, `[`, `]`, newlines,
/// or leading/trailing whitespace).
fn appendStringValue(builder: *jsc.wtf.StringBuilder, str: bun.String) void {
    var needs_quoting = false;

    for (0..str.length()) |i| {
        const c = str.charAt(i);
        switch (c) {
            ';', '#', '[', ']', '\n', '\r', '"' => {
                needs_quoting = true;
                break;
            },
            else => {},
        }
    }

    if (!needs_quoting and str.length() > 0) {
        const first_c = str.charAt(0);
        const last_c = str.charAt(str.length() - 1);
        if (first_c == ' ' or first_c == '\t' or last_c == ' ' or last_c == '\t') {
            needs_quoting = true;
        }
    }

    if (needs_quoting) {
        builder.append(.lchar, '"');
        for (0..str.length()) |i| {
            const c = str.charAt(i);
            switch (c) {
                '"' => builder.append(.latin1, "\\\""),
                '\\' => builder.append(.latin1, "\\\\"),
                '\n' => builder.append(.latin1, "\\n"),
                '\r' => builder.append(.latin1, "\\r"),
                else => builder.append(.uchar, c),
            }
        }
        builder.append(.lchar, '"');
    } else {
        builder.append(.string, str);
    }
}

