import { expect, test, describe } from "bun:test";

describe("Bun.INI.parse", () => {
  test("parses simple key=value pairs", () => {
    const result = Bun.INI.parse("name = Alice\nage = 30");
    expect(result).toEqual({ name: "Alice", age: "30" });
  });

  test("parses key=value without spaces around =", () => {
    const result = Bun.INI.parse("host=localhost\nport=5432");
    expect(result).toEqual({ host: "localhost", port: "5432" });
  });

  test("parses sections as nested objects", () => {
    const result = Bun.INI.parse("[db]\nhost = localhost\nport = 5432");
    expect(result).toEqual({ db: { host: "localhost", port: "5432" } });
  });

  test("parses multiple sections", () => {
    const ini = `
[alpha]
x = 1

[beta]
y = 2
`;
    const result = Bun.INI.parse(ini);
    expect(result).toEqual({ alpha: { x: "1" }, beta: { y: "2" } });
  });

  test("parses keys before any section at the root level", () => {
    const ini = `
debug = true

[server]
host = 0.0.0.0
`;
    const result = Bun.INI.parse(ini);
    expect(result).toEqual({ debug: "true", server: { host: "0.0.0.0" } });
  });

  test("skips semicolon comment lines", () => {
    const ini = `
; this is a comment
key = value
`;
    const result = Bun.INI.parse(ini);
    expect(result).toEqual({ key: "value" });
  });

  test("skips hash comment lines", () => {
    const ini = `
# another comment
key = value
`;
    const result = Bun.INI.parse(ini);
    expect(result).toEqual({ key: "value" });
  });

  test("strips inline semicolon comments from unquoted values", () => {
    const result = Bun.INI.parse("key = hello ; inline comment");
    expect(result).toEqual({ key: "hello" });
  });

  test("strips inline hash comments from unquoted values", () => {
    const result = Bun.INI.parse("key = hello # inline comment");
    expect(result).toEqual({ key: "hello" });
  });

  test("handles double-quoted values", () => {
    const result = Bun.INI.parse('key = "hello world"');
    expect(result).toEqual({ key: "hello world" });
  });

  test("handles single-quoted values", () => {
    const result = Bun.INI.parse("key = 'hello world'");
    expect(result).toEqual({ key: "hello world" });
  });

  test("preserves semicolons inside double-quoted values", () => {
    const result = Bun.INI.parse('url = "http://example.com?a=1;b=2"');
    expect(result).toEqual({ url: "http://example.com?a=1;b=2" });
  });

  test("handles empty values", () => {
    const result = Bun.INI.parse("empty = ");
    expect(result).toEqual({ empty: "" });
  });

  test("skips empty lines", () => {
    const result = Bun.INI.parse("\n\nkey = value\n\n");
    expect(result).toEqual({ key: "value" });
  });

  test("handles Windows-style CRLF line endings", () => {
    const result = Bun.INI.parse("a = 1\r\nb = 2\r\n");
    expect(result).toEqual({ a: "1", b: "2" });
  });

  test("throws on non-string argument", () => {
    expect(() => Bun.INI.parse(null as any)).toThrow();
  });

  test("handles values containing = sign", () => {
    const result = Bun.INI.parse("url = http://example.com?a=1&b=2");
    expect(result).toEqual({ url: "http://example.com?a=1&b=2" });
  });

  test("trims whitespace from section names", () => {
    const result = Bun.INI.parse("[ section ]\nkey = val");
    expect(result).toEqual({ section: { key: "val" } });
  });
});

describe("Bun.INI.stringify", () => {
  test("stringifies a flat object", () => {
    const result = Bun.INI.stringify({ name: "Alice", age: 30 });
    // Both key = value lines must appear
    expect(result).toContain("name = Alice");
    expect(result).toContain("age = 30");
  });

  test("stringifies nested objects as sections", () => {
    const result = Bun.INI.stringify({ db: { host: "localhost", port: 5432 } });
    expect(result).toContain("[db]");
    expect(result).toContain("host = localhost");
    expect(result).toContain("port = 5432");
  });

  test("writes top-level primitives before sections", () => {
    const result = Bun.INI.stringify({ debug: true, server: { host: "0.0.0.0" } });
    const debugIdx = result.indexOf("debug = true");
    const sectionIdx = result.indexOf("[server]");
    expect(debugIdx).toBeGreaterThanOrEqual(0);
    expect(sectionIdx).toBeGreaterThan(debugIdx);
  });

  test("stringifies boolean values", () => {
    const result = Bun.INI.stringify({ enabled: true, disabled: false });
    expect(result).toContain("enabled = true");
    expect(result).toContain("disabled = false");
  });

  test("stringifies number values", () => {
    const result = Bun.INI.stringify({ count: 42, ratio: 3.14 });
    expect(result).toContain("count = 42");
    expect(result).toContain("ratio = 3.14");
  });

  test("quotes string values containing semicolons", () => {
    const result = Bun.INI.stringify({ key: "val;ue" });
    expect(result).toContain('"val;ue"');
  });

  test("quotes string values containing hash signs", () => {
    const result = Bun.INI.stringify({ key: "val#ue" });
    expect(result).toContain('"val#ue"');
  });

  test("quotes string values with leading whitespace", () => {
    const result = Bun.INI.stringify({ key: " leading" });
    expect(result).toContain('" leading"');
  });

  test("quotes string values with trailing whitespace", () => {
    const result = Bun.INI.stringify({ key: "trailing " });
    expect(result).toContain('"trailing "');
  });

  test("round-trips a simple object", () => {
    const original = { host: "localhost", port: "5432" };
    const ini = Bun.INI.stringify(original);
    const parsed = Bun.INI.parse(ini);
    expect(parsed).toEqual(original);
  });

  test("round-trips a nested object", () => {
    const original = { db: { host: "localhost", port: "5432" } };
    const ini = Bun.INI.stringify(original as any);
    const parsed = Bun.INI.parse(ini);
    expect(parsed).toEqual(original);
  });

  test("stringifies null value as empty", () => {
    const result = Bun.INI.stringify({ key: null });
    expect(result).toContain("key = ");
  });

  test("skips undefined values", () => {
    const result = Bun.INI.stringify({ a: "x", b: undefined });
    expect(result).not.toContain("b =");
    expect(result).toContain("a = x");
  });

  test("stringifies array values as comma-separated", () => {
    const result = Bun.INI.stringify({ tags: ["one", "two", "three"] });
    expect(result).toContain("tags = one,two,three");
  });

  test("throws on non-object input", () => {
    expect(() => Bun.INI.stringify("not an object" as any)).toThrow();
  });

  test("returns undefined for undefined input", () => {
    const result = Bun.INI.stringify(undefined as any);
    expect(result).toBeUndefined();
  });
});

