/**
 * Tests for the public Bun.INI namespace (parse and stringify).
 * This tests the Zig-implemented INIObject, not the internal npm-compatible parser.
 */
import { expect, test, describe } from "bun:test";

describe("Bun.INI.parse", () => {
  test("parses simple key=value pairs", () => {
    expect(Bun.INI.parse("name = Alice\nage = 30")).toEqual({ name: "Alice", age: "30" });
  });

  test("parses key=value without spaces around =", () => {
    expect(Bun.INI.parse("host=localhost\nport=5432")).toEqual({ host: "localhost", port: "5432" });
  });

  test("parses a section as a nested object", () => {
    expect(Bun.INI.parse("[db]\nhost = localhost\nport = 5432")).toEqual({
      db: { host: "localhost", port: "5432" },
    });
  });

  test("parses multiple sections", () => {
    const ini = "[alpha]\nx = 1\n\n[beta]\ny = 2\n";
    expect(Bun.INI.parse(ini)).toEqual({ alpha: { x: "1" }, beta: { y: "2" } });
  });

  test("puts keys before any section on the root object", () => {
    const ini = "debug = true\n\n[server]\nhost = 0.0.0.0\n";
    expect(Bun.INI.parse(ini)).toEqual({ debug: "true", server: { host: "0.0.0.0" } });
  });

  test("skips semicolon comment lines", () => {
    expect(Bun.INI.parse("; comment\nkey = value")).toEqual({ key: "value" });
  });

  test("skips hash comment lines", () => {
    expect(Bun.INI.parse("# comment\nkey = value")).toEqual({ key: "value" });
  });

  test("strips inline semicolon comment from unquoted value", () => {
    expect(Bun.INI.parse("key = hello ; inline")).toEqual({ key: "hello" });
  });

  test("strips inline hash comment from unquoted value", () => {
    expect(Bun.INI.parse("key = hello # inline")).toEqual({ key: "hello" });
  });

  test("handles double-quoted values", () => {
    expect(Bun.INI.parse('key = "hello world"')).toEqual({ key: "hello world" });
  });

  test("handles single-quoted values", () => {
    expect(Bun.INI.parse("key = 'hello world'")).toEqual({ key: "hello world" });
  });

  test("preserves semicolons inside double-quoted values", () => {
    expect(Bun.INI.parse('url = "http://example.com?a=1;b=2"')).toEqual({
      url: "http://example.com?a=1;b=2",
    });
  });

  test("handles empty values", () => {
    expect(Bun.INI.parse("empty = ")).toEqual({ empty: "" });
  });

  test("skips empty lines", () => {
    expect(Bun.INI.parse("\n\nkey = value\n\n")).toEqual({ key: "value" });
  });

  test("handles CRLF line endings", () => {
    expect(Bun.INI.parse("a = 1\r\nb = 2\r\n")).toEqual({ a: "1", b: "2" });
  });

  test("preserves = signs inside values", () => {
    expect(Bun.INI.parse("url = http://example.com?a=1&b=2")).toEqual({
      url: "http://example.com?a=1&b=2",
    });
  });

  test("trims whitespace around section names", () => {
    expect(Bun.INI.parse("[ section ]\nkey = val")).toEqual({ section: { key: "val" } });
  });

  test("throws on null input", () => {
    expect(() => Bun.INI.parse(null as any)).toThrow();
  });

  test("throws on undefined input", () => {
    expect(() => Bun.INI.parse(undefined as any)).toThrow();
  });
});

describe("Bun.INI.stringify", () => {
  test("stringifies a flat object", () => {
    const result = Bun.INI.stringify({ name: "Alice", age: 30 });
    expect(result).toContain("name = Alice");
    expect(result).toContain("age = 30");
  });

  test("stringifies a nested object as a section", () => {
    const result = Bun.INI.stringify({ db: { host: "localhost", port: 5432 } } as any);
    expect(result).toContain("[db]");
    expect(result).toContain("host = localhost");
    expect(result).toContain("port = 5432");
  });

  test("writes top-level scalars before sections", () => {
    const result = Bun.INI.stringify({ debug: true, server: { host: "0.0.0.0" } } as any);
    const scalarIdx = result.indexOf("debug = true");
    const sectionIdx = result.indexOf("[server]");
    expect(scalarIdx).toBeGreaterThanOrEqual(0);
    expect(sectionIdx).toBeGreaterThan(scalarIdx);
  });

  test("stringifies booleans", () => {
    const result = Bun.INI.stringify({ enabled: true, disabled: false });
    expect(result).toContain("enabled = true");
    expect(result).toContain("disabled = false");
  });

  test("stringifies integers", () => {
    expect(Bun.INI.stringify({ count: 42 })).toContain("count = 42");
  });

  test("stringifies floats", () => {
    const result = Bun.INI.stringify({ ratio: 3.14 });
    expect(result).toContain("ratio = 3.14");
  });

  test("quotes string values containing semicolons", () => {
    expect(Bun.INI.stringify({ key: "val;ue" })).toContain('"val;ue"');
  });

  test("quotes string values containing hash signs", () => {
    expect(Bun.INI.stringify({ key: "val#ue" })).toContain('"val#ue"');
  });

  test("quotes string values with leading whitespace", () => {
    expect(Bun.INI.stringify({ key: " leading" })).toContain('" leading"');
  });

  test("quotes string values with trailing whitespace", () => {
    expect(Bun.INI.stringify({ key: "trailing " })).toContain('"trailing "');
  });

  test("round-trips a flat object", () => {
    const original = { host: "localhost", port: "5432" };
    const ini = Bun.INI.stringify(original);
    expect(Bun.INI.parse(ini)).toEqual(original);
  });

  test("round-trips a nested object", () => {
    const original = { db: { host: "localhost", port: "5432" } };
    const ini = Bun.INI.stringify(original as any);
    expect(Bun.INI.parse(ini)).toEqual(original);
  });

  test("stringifies null as an empty value", () => {
    expect(Bun.INI.stringify({ key: null })).toContain("key = ");
  });

  test("skips undefined values", () => {
    const result = Bun.INI.stringify({ a: "x", b: undefined });
    expect(result).toContain("a = x");
    expect(result).not.toContain("b = ");
  });

  test("stringifies array values as comma-separated", () => {
    const result = Bun.INI.stringify({ tags: ["one", "two", "three"] });
    expect(result).toContain("tags = one,two,three");
  });

  test("returns undefined for undefined input", () => {
    expect(Bun.INI.stringify(undefined as any)).toBeUndefined();
  });

  test("throws on non-object input", () => {
    expect(() => Bun.INI.stringify("not an object" as any)).toThrow();
  });

  test("skips function values", () => {
    const result = Bun.INI.stringify({ fn: () => {}, key: "value" });
    expect(result).not.toContain("fn");
    expect(result).toContain("key = value");
  });
});

